import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { registrarVenta } from '../services/ventaService';

const Ventas = () => {
    const navigate = useNavigate();
    const [codigo, setCodigo] = useState('');
    const [ventaRealizada, setVentaRealizada] = useState(null);

    // Seguridad: Si no hay sesión de riempy, lo saca
    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) navigate("/");
    }, [navigate]);

    const handleVenta = async (e) => {
        e.preventDefault();
        const matricula = localStorage.getItem('usuarioLogueado');
        
        const datos = {
            codigoProducto: codigo,
            cantidad: 1,
            precioVenta: 250.00, // Aquí podrías jalar el precio real del producto
            vendedorMatricula: matricula
        };

        const resultado = await registrarVenta(datos);
        if (resultado) {
            setVentaRealizada(resultado);
            alert("✅ Venta exitosa. El inventario se ha actualizado.");
            // Pequeño delay para que React renderice el ticket antes de imprimir
            setTimeout(() => window.print(), 500);
            setCodigo(''); // Limpiar para la siguiente venta
        } else {
            alert("❌ Error: Verifica el stock o el código del producto.");
        }
    };

    return (
        <div style={{ padding: '20px' }}>
            {/* Sección que se oculta al imprimir */}
            <div className="no-print">
                <h2>🛒 Terminal de Venta - Isla Tecnológica</h2>
                <form onSubmit={handleVenta} style={{ marginBottom: '20px' }}>
                    <input 
                        placeholder="Escribe el código de la funda/mica" 
                        value={codigo} 
                        onChange={(e) => setCodigo(e.target.value)} 
                        style={{ padding: '10px', width: '250px', borderRadius: '5px' }}
                        required
                    />
                    <button type="submit" style={{ padding: '10px 20px', marginLeft: '10px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
                        Cobrar e Imprimir Ticket
                    </button>
                </form>
                <button onClick={() => navigate("/inventario")} style={{ padding: '10px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
                    Volver al Inventario
                </button>
            </div>

            {/* DISEÑO DEL TICKET (Solo visible en la impresión) */}
            <div id="ticket-impresion" className="print-only" style={{ display: 'none', textAlign: 'center', width: '80mm', fontFamily: 'monospace', padding: '10px' }}>
                <h2 style={{ margin: '0' }}>ISLA TECNOLÓGICA</h2>
                <p>--------------------------------</p>
                <p>Ticket de Venta: #{ventaRealizada?.id}</p>
                <p>Fecha: {new Date().toLocaleString()}</p>
                <p>--------------------------------</p>
                <div style={{ textAlign: 'left' }}>
                    <p>Cod: {ventaRealizada?.codigoProducto}</p>
                    <p>Cant: 1</p>
                    <p>Total: ${ventaRealizada?.total?.toFixed(2)}</p>
                </div>
                <p>--------------------------------</p>
                <p>Atendido por: {ventaRealizada?.vendedorMatricula}</p>
                <p>¡Gracias por tu compra!</p>
            </div>
        </div>
    );
};

export default Ventas;
